// MARK: - Universal Link Handler Service

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private var navigator: DeepLinkNavigator?
    private var pendingRoute: DeepLinkRoute?
    private var isReady = false
    
    private init() {}
    
    func configure(with window: UIWindow?) {
        navigator = DeepLinkNavigator(window: window)
        isReady = true
        
        // Process any pending route that arrived before the app was ready
        if let pending = pendingRoute {
            navigate(to: pending)
            pendingRoute = nil
        }
    }
    
    func handleUniversalLink(_ url: URL) -> Bool {
        print("UniversalLinkHandler: Received URL - \(url.absoluteString)")
        
        let route = DeepLinkParser.parse(url: url)
        
        guard case .unknown = route else {
            // Valid route
            navigate(to: route)
            logDeepLinkEvent(url: url, route: route)
            return true
        }
        
        print("UniversalLinkHandler: Unrecognized URL pattern - \(url.absoluteString)")
        return false
    }
    
    private func navigate(to route: DeepLinkRoute) {
        if isReady {
            // Small delay to ensure UI is ready
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) { [weak self] in
                self?.navigator?.navigate(to: route)
            }
        } else {
            pendingRoute = route
        }
    }
    
    // Analytics tracking for marketing campaigns
    private func logDeepLinkEvent(url: URL, route: DeepLinkRoute) {
        let components = URLComponents(url: url, resolvingAgainstBaseURL: true)
        let queryItems = components?.queryItems ?? []
        
        let campaign = queryItems.first(where: { $0.name == "utm_campaign" })?.value
        let source = queryItems.first(where: { $0.name == "utm_source" })?.value
        let medium = queryItems.first(where: { $0.name == "utm_medium" })?.value
        
        var eventParams: [String: String] = [
            "url": url.absoluteString,
            "route": String(describing: route)
        ]
        
        if let campaign = campaign { eventParams["utm_campaign"] = campaign }
        if let source = source { eventParams["utm_source"] = source }
        if let medium = medium { eventParams["utm_medium"] = medium }
        
        print("DeepLink Analytics Event: \(eventParams)")
        // TODO: Send to your analytics service (Firebase, Mixpanel, etc.)
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        
        // Set up your root view controller
        let rootVC = UINavigationController(rootViewController: HomeViewController())
        window.rootViewController = rootVC
        window.makeKeyAndVisible()
        self.window = window
        
        // Configure the universal link handler
        UniversalLinkHandler.shared.configure(with: window)
        
        // Handle universal link if app was launched via one
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            _ = UniversalLinkHandler.shared.handleUniversalLink(url)
        }
    }
    
    // Handle universal links when app is already running
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        _ = UniversalLinkHandler.shared.handleUniversalLink(url)
    }
}

